class MyApp extends StatelessWidget {
  final AuthManager authManager;

  const MyApp({super.key, required this.authManager});

  @override
  Widget build(BuildContext context) {
    return ListenableBuilder(
      listenable: authManager,
      builder: (context, _) {
        return MaterialApp(
          title: 'Auth Manager Demo',
          debugShowCheckedModeBanner: false,
          theme: ThemeData(
            colorSchemeSeed: Colors.deepPurple,
            useMaterial3: true,
            brightness: Brightness.light,
          ),
          home: _buildHome(),
        );
      },
    );
  }

  Widget _buildHome() {
    switch (authManager.state.status) {
      case AuthStatus.unknown:
        return const SplashScreen();
      case AuthStatus.authenticated:
        return HomeScreen(authManager: authManager);
      case AuthStatus.unauthenticated:
        return AuthScreen(authManager: authManager);
    }
  }
}

